<template><section class="space-y-6 pt-20"><div class="surface-card p-6"><p class="section-kicker">Rankings</p><h1>影片排行榜</h1><div class="flex flex-wrap gap-3"><button v-for="item in types" :key="item.value" class="pill-button" :class="{'is-active':type===item.value}" @click="select(item.value)">{{item.label}}</button></div></div><MovieList :movies="movies"/><el-empty v-if="!loading&&!movies.length" description="暂无排行数据"/></section></template>
<script setup>import{onMounted,ref}from'vue';import{getRankings}from'@/api/movie';import MovieList from'@/components/MovieList.vue';const type=ref('rating'),movies=ref([]),loading=ref(false),types=[{value:'rating',label:'高分榜'},{value:'favorite',label:'收藏榜'},{value:'view',label:'浏览榜'},{value:'latest',label:'最新榜'},{value:'user-rating',label:'用户评分榜'}];async function select(v){type.value=v;loading.value=true;try{movies.value=(await getRankings({type:v})).data||[]}finally{loading.value=false}}onMounted(()=>select(type.value))</script>